package sandbox

import (
	"bytes"
	"context"
	"os"
	"runtime"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
)

// e2eRootfsPath returns the path to the rootfs image for e2e tests.
// Set SANDBOX_E2E_ROOTFS environment variable to specify a custom path.
func e2eRootfsPath() string {
	if path := os.Getenv("SANDBOX_E2E_ROOTFS"); path != "" {
		return path
	}
	return ""
}

// skipE2E skips the test if e2e prerequisites are not met.
func skipE2E(t *testing.T) {
	t.Helper()

	// Check platform support
	switch runtime.GOOS {
	case "linux":
		if _, err := os.Stat("/dev/kvm"); os.IsNotExist(err) {
			t.Skip("KVM not available")
		}
	case "darwin":
		if runtime.GOARCH != "arm64" {
			t.Skip("Apple Silicon required for macOS")
		}
	default:
		t.Skipf("unsupported platform: %s", runtime.GOOS)
	}

	// Check rootfs image
	if e2eRootfsPath() == "" {
		t.Skip("SANDBOX_E2E_ROOTFS not set - set to path of rootfs image to run e2e tests")
	}

	if _, err := os.Stat(e2eRootfsPath()); os.IsNotExist(err) {
		t.Skipf("rootfs image not found: %s", e2eRootfsPath())
	}
}

// setupE2EExecutor creates a sandbox executor for e2e testing using the real runtime.
func setupE2EExecutor(t *testing.T, config Config) *Executor {
	t.Helper()
	skipE2E(t)

	if config.WorkspaceRoot == "" {
		config.WorkspaceRoot = t.TempDir()
	}

	if config.Image == "" {
		config.Image = e2eRootfsPath()
	}

	ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
	defer cancel()

	exec, err := New(ctx, config)
	require.NoError(t, err)
	t.Cleanup(func() { _ = exec.Close() })

	return exec
}

func runCommand(t *testing.T, exec *Executor, command string) (string, string) {
	t.Helper()

	stdout := &bytes.Buffer{}
	stderr := &bytes.Buffer{}
	watchCh := make(chan error, 1)

	cmd := workspaceapi.Cmd{
		Path:    "/bin/sh",
		Args:    []string{"-c", command},
		Stdout:  stdout,
		Stderr:  stderr,
		Watcher: &e2eWatcher{ch: watchCh},
	}

	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	_, err := exec.Start(ctx, cmd)
	require.NoError(t, err)

	select {
	case <-watchCh:
	case <-ctx.Done():
		t.Fatalf("timeout waiting for command: %s", command)
	}

	return stdout.String(), stderr.String()
}

// e2eWatcher implements workspaceapi.ProcessWatcher for e2e tests.
type e2eWatcher struct {
	ch chan error
}

func (w *e2eWatcher) WatchProcess() chan error {
	return w.ch
}

func TestE2E_SimpleCommand(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	stdout, _ := runCommand(t, exec, "echo hello")
	assert.Equal(t, "hello\n", stdout)
}

func TestE2E_EnvironmentVariables(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	tsuite := []struct {
		name    string
		cmd     string
		wantOut string
	}{
		{
			name:    "echo with var",
			cmd:     "export FOO=bar && echo $FOO",
			wantOut: "bar\n",
		},
		{
			name:    "multiple vars",
			cmd:     "export A=1 B=2 && echo $A$B",
			wantOut: "12\n",
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			stdout, _ := runCommand(t, exec, tc.cmd)
			assert.Equal(t, tc.wantOut, stdout)
		})
	}
}

func TestE2E_WorkingDirectory(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	stdout, _ := runCommand(t, exec, "pwd")
	// Verify we get some path output
	assert.NotEmpty(t, stdout)
}

func TestE2E_StderrCapture(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	stdout, stderr := runCommand(t, exec, "echo out; echo err >&2")
	assert.Equal(t, "out\n", stdout)
	assert.Equal(t, "err\n", stderr)
}

func TestE2E_ExitCode(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	watchCh := make(chan error, 1)
	cmd := workspaceapi.Cmd{
		Path:    "/bin/sh",
		Args:    []string{"-c", "exit 42"},
		Watcher: &e2eWatcher{ch: watchCh},
	}

	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	_, err := exec.Start(ctx, cmd)
	require.NoError(t, err)

	select {
	case werr := <-watchCh:
		require.Error(t, werr)
		assert.Contains(t, werr.Error(), "42")
	case <-ctx.Done():
		t.Fatal("timeout")
	}
}

func TestE2E_ResourceLimits(t *testing.T) {
	tsuite := []struct {
		name      string
		resources ResourceConfig
		cmd       string
		wantErr   string
	}{
		{
			name:      "memory limit OOM",
			resources: ResourceConfig{CPUs: 1, MemoryMB: 64, DiskMB: 1024},
			cmd:       "head -c 128M /dev/zero | cat > /dev/null",
			wantErr:   "killed",
		},
		{
			name:      "disk quota exceeded",
			resources: ResourceConfig{CPUs: 1, MemoryMB: 256, DiskMB: 10},
			cmd:       "dd if=/dev/zero of=/tmp/big bs=1M count=20 2>&1",
			wantErr:   "No space left",
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			config := DefaultConfig()
			config.Resources = &tc.resources
			exec := setupE2EExecutor(t, config)
			_, stderr := runCommand(t, exec, tc.cmd)
			assert.Contains(t, stderr, tc.wantErr)
		})
	}
}

func TestE2E_NetworkPolicy(t *testing.T) {
	tsuite := []struct {
		name         string
		allowedHosts []string
		targetHost   string
		wantAllowed  bool
	}{
		{
			name:         "default deny",
			allowedHosts: nil,
			targetHost:   "example.com",
			wantAllowed:  false,
		},
		{
			name:         "allowed host",
			allowedHosts: []string{"api.github.com"},
			targetHost:   "api.github.com",
			wantAllowed:  true,
		},
		{
			name:         "blocked host",
			allowedHosts: []string{"api.github.com"},
			targetHost:   "google.com",
			wantAllowed:  false,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			config := DefaultConfig()
			if tc.allowedHosts != nil {
				config.Policy.Network.AllowedHosts = tc.allowedHosts
			}
			exec := setupE2EExecutor(t, config)

			// Try to connect to the target host
			cmd := "curl -s --connect-timeout 5 https://" + tc.targetHost + " >/dev/null 2>&1 && echo OK || echo BLOCKED"
			stdout, _ := runCommand(t, exec, cmd)

			if tc.wantAllowed {
				assert.Contains(t, stdout, "OK")
			} else {
				assert.Contains(t, stdout, "BLOCKED")
			}
		})
	}
}

func TestE2E_ProcessIsolation(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	// Get PIDs visible inside sandbox
	stdout, _ := runCommand(t, exec, "ps -eo pid --no-headers | wc -l")

	// In an isolated VM, we should see very few processes (init, sh, ps)
	// Not thousands like on a typical host
	assert.NotEmpty(t, stdout)
}

func TestE2E_EphemeralFilesystem(t *testing.T) {
	config := DefaultConfig()
	config.Policy.Filesystem.EphemeralRoot = true

	// First sandbox - create file
	exec1 := setupE2EExecutor(t, config)
	runCommand(t, exec1, "echo 'secret' > /tmp/testfile")
	_ = exec1.Close()

	// Second sandbox - file should not exist
	exec2 := setupE2EExecutor(t, config)
	_, stderr := runCommand(t, exec2, "cat /tmp/testfile")
	assert.Contains(t, stderr, "No such file")
}

func TestE2E_EnvironmentScrubbing(t *testing.T) {
	tsuite := []struct {
		name     string
		envVar   string
		envValue string
	}{
		{name: "github token", envVar: "GITHUB_TOKEN", envValue: "ghp_secret123"},
		{name: "aws secret", envVar: "AWS_SECRET_ACCESS_KEY", envValue: "wJalrXUtnFEMI"},
		{name: "api key", envVar: "API_KEY", envValue: "sk-proj-abc123"},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			t.Setenv(tc.envVar, tc.envValue)
			exec := setupE2EExecutor(t, DefaultConfig())
			stdout, _ := runCommand(t, exec, "env")
			assert.NotContains(t, stdout, tc.envValue)
		})
	}
}

func TestE2E_WorkspaceMount(t *testing.T) {
	config := DefaultConfig()
	config.WorkspaceRoot = t.TempDir()

	// Create a file in the workspace
	testFile := config.WorkspaceRoot + "/test.txt"
	err := os.WriteFile(testFile, []byte("hello from host"), 0644)
	require.NoError(t, err)

	exec := setupE2EExecutor(t, config)

	// Verify the file is visible in the sandbox
	stdout, _ := runCommand(t, exec, "cat /workspace/test.txt")
	assert.Equal(t, "hello from host", stdout)

	// Write a file from inside the sandbox
	runCommand(t, exec, "echo 'hello from sandbox' > /workspace/sandbox.txt")

	// Verify it's visible on the host
	content, err := os.ReadFile(config.WorkspaceRoot + "/sandbox.txt")
	require.NoError(t, err)
	assert.Equal(t, "hello from sandbox\n", string(content))
}

