    14→
    15→// Package sandbox provides a secure execution environment for running
    16→// commands from extensions. Commands run inside an isolated virtual machine,
    17→// protecting the host system from malicious or buggy extension code.
    18→package sandbox
    19→
    20→import (
    21→	"bytes"
    22→	"context"
    23→	"errors"
    24→	"fmt"
    25→	"io"
    26→	"log/slog"
    27→	"net"
    28→	"strings"
    29→	"sync"
    30→	"sync/atomic"
    31→	"syscall"
    32→	"time"
    33→
    34→	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
    35→	"github.com/unstablebuild/rune-go-sdk/sandbox/policy"
    36→	"github.com/unstablebuild/rune-go-sdk/sandbox/sandboxrpc"
    37→	"google.golang.org/grpc"
    38→	"google.golang.org/grpc/credentials/insecure"
    39→)
    40→
    41→const agentConnectTimeout = 30 * time.Second
    42→
    43→// Ensure Executor implements workspaceapi.Executor
    44→var _ workspaceapi.Executor = (*Executor)(nil)
    45→
    46→// Executor implements workspaceapi.Executor by running commands inside a
    47→// sandboxed virtual machine.
    48→type Executor struct {
    49→	config  Config
    50→	runtime Runtime
    51→	vm      VM
    52→	agent   *sandboxrpc.Client
    53→	conn    *grpc.ClientConn
    54→	log     *slog.Logger
    55→
    56→	// For ExecutableVM mode
    57→	execVM     ExecutableVM
    58→	pidCounter atomic.Int64
    59→	processes  sync.Map // map[workspaceapi.Pid]context.CancelFunc
    60→
    61→	mu     sync.RWMutex
    62→	closed bool
    63→}
    64→
    65→// Option is a functional option for configuring an Executor.
    66→type Option func(*Executor)
    67→
    68→// WithRuntime sets a custom runtime for the executor.
    69→// This is primarily used for testing.
    70→func WithRuntime(r Runtime) Option {
    71→	return func(e *Executor) {
    72→		e.runtime = r
    73→	}
    74→}
    75→
    76→// WithLogger sets a custom logger for the executor.
    77→func WithLogger(log *slog.Logger) Option {
    78→	return func(e *Executor) {
    79→		e.log = log
    80→	}
    81→}
    82→
    83→// New creates a new sandbox executor. The VM is started immediately and
    84→// will be ready to accept commands upon return. The caller is responsible
    85→// for calling Close() when the executor is no longer needed.
    86→func New(ctx context.Context, config Config, opts ...Option) (*Executor, error) {
    87→	e := &Executor{
    88→		config: config,
    89→		log:    slog.Default().With("struct", "sandbox.Executor"),
    90→	}
    91→
    92→	for _, opt := range opts {
    93→		opt(e)
    94→	}
    95→
    96→	// Use default runtime if not provided
    97→	if e.runtime == nil {
    98→		runtime, err := NewRuntime()
    99→		if err != nil {
   100→			return nil, fmt.Errorf("create runtime: %w", err)
   101→		}
   102→		e.runtime = runtime
   103→	}
   104→
   105→	// Create the VM
   106→	vm, err := e.runtime.Create(ctx, &config)
   107→	if err != nil {
   108→		return nil, fmt.Errorf("create vm: %w", err)
   109→	}
   110→	e.vm = vm
   111→
   112→	// Check if VM supports direct execution (e.g., Matchlock VMs)
   113→	if execVM, ok := vm.(ExecutableVM); ok {
   114→		e.execVM = execVM
   115→		e.log.Info("sandbox executor ready (direct exec)", "vm_id", vm.ID())
   116→		return e, nil
   117→	}
   118→
   119→	// Fall back to gRPC agent connection
   120→	if err := e.connectAgent(ctx); err != nil {
   121→		_ = vm.Close()
   122→		return nil, fmt.Errorf("connect agent: %w", err)
   123→	}
   124→
   125→	e.log.Info("sandbox executor ready (agent)", "vm_id", vm.ID())
   126→	return e, nil
   127→}
   128→
   129→func (e *Executor) connectAgent(ctx context.Context) error {
   130→	timeoutCtx, cancel := context.WithTimeout(ctx, agentConnectTimeout)
   131→	defer cancel()
   132→
   133→	// Get connection to the agent
   134→	agentConn, err := e.vm.AgentConn()
   135→	if err != nil {
   136→		return fmt.Errorf("get agent connection: %w", err)
   137→	}
   138→
   139→	// Create gRPC connection over the net.Conn
   140→	grpcConn, err := grpc.NewClient(
   141→		"passthrough:///sandbox",
   142→		grpc.WithTransportCredentials(insecure.NewCredentials()),
   143→		grpc.WithContextDialer(func(_ context.Context, _ string) (net.Conn, error) {
   144→			return agentConn, nil
   145→		}),
   146→	)
   147→	if err != nil {
   148→		_ = agentConn.Close()
   149→		return fmt.Errorf("create grpc connection: %w", err)
   150→	}
