// Package policy provides security policy definitions for sandbox execution.
package policy

// Policy combines all security constraints for a sandbox.
type Policy struct {
	// Network contains network access policies.
	Network *NetworkPolicy

	// Filesystem contains filesystem access policies.
	Filesystem *FilesystemPolicy

	// Environment contains environment variable policies.
	Environment *EnvironmentPolicy

	// Audit contains audit logging configuration.
	Audit *AuditPolicy
}

// AuditPolicy contains configuration for audit logging.
