	// LogCommands enables logging of all commands executed.
	LogCommands bool

	// LogNetwork enables logging of network connections.
	LogNetwork bool

	// LogFilesystem enables logging of filesystem operations.
	LogFilesystem bool
}

// DefaultPolicy returns a Policy with secure defaults.
func DefaultPolicy() *Policy {
	return &Policy{
		Network:     DefaultNetworkPolicy(),
		Filesystem:  DefaultFilesystemPolicy(),
		Environment: DefaultEnvironmentPolicy(),
		Audit:       DefaultAuditPolicy(),
	}
}

// DefaultAuditPolicy returns an AuditPolicy with defaults.
func DefaultAuditPolicy() *AuditPolicy {
	return &AuditPolicy{
		LogCommands:   true,
		LogNetwork:    false,
		LogFilesystem: false,
	}
}

