package policy

import (
	"regexp"
	"strings"
)

// EnvironmentPolicy contains configuration for environment variable handling.
type EnvironmentPolicy struct {
	// ScrubSensitive enables automatic scrubbing of sensitive env vars.
	ScrubSensitive bool

	// AllowedVars is an allowlist of env var names to pass through.
	// If empty, all non-sensitive vars are passed.
	AllowedVars []string

	// BlockedVars is a blocklist of env var names to always remove.
	BlockedVars []string

	// BlockedPatterns are regex patterns for env var names to block.
	BlockedPatterns []string

	// compiledPatterns caches compiled regex patterns.
	compiledPatterns []*regexp.Regexp
}

// DefaultEnvironmentPolicy returns an EnvironmentPolicy with secure defaults.
func DefaultEnvironmentPolicy() *EnvironmentPolicy {
	return &EnvironmentPolicy{
		ScrubSensitive: true,
		BlockedVars: []string{
			// Common secret/token vars
			"GITHUB_TOKEN",
			"GH_TOKEN",
			"GITLAB_TOKEN",
			"AWS_SECRET_ACCESS_KEY",
			"AWS_SESSION_TOKEN",
			"AZURE_CLIENT_SECRET",
			"GOOGLE_APPLICATION_CREDENTIALS",
			"OPENAI_API_KEY",
			"ANTHROPIC_API_KEY",
			"CLAUDE_API_KEY",
			"NPM_TOKEN",
			"DOCKER_PASSWORD",
			"DOCKER_AUTH_CONFIG",
			// Database credentials
			"DATABASE_PASSWORD",
			"DB_PASSWORD",
			"MYSQL_PASSWORD",
			"POSTGRES_PASSWORD",
			"REDIS_PASSWORD",
			"MONGO_PASSWORD",
			// SSH/signing keys
			"SSH_PRIVATE_KEY",
			"GPG_PRIVATE_KEY",
			"SIGNING_KEY",
		},
		BlockedPatterns: []string{
			`(?i).*_SECRET.*`,
			`(?i).*_TOKEN$`,
			`(?i).*_API_KEY$`,
			`(?i).*_PASSWORD$`,
			`(?i).*_PRIVATE_KEY$`,
			`(?i).*_CREDENTIALS$`,
		},
	}
}

// ScrubEnvironment filters environment variables according to the policy.
// It takes env vars in KEY=value format and returns filtered vars.
func (p *EnvironmentPolicy) ScrubEnvironment(env []string) []string {
	if p == nil || !p.ScrubSensitive {
		return env
	}

	// Compile patterns on first use
	if p.compiledPatterns == nil && len(p.BlockedPatterns) > 0 {
		p.compiledPatterns = make([]*regexp.Regexp, 0, len(p.BlockedPatterns))
		for _, pattern := range p.BlockedPatterns {
			if re, err := regexp.Compile(pattern); err == nil {
				p.compiledPatterns = append(p.compiledPatterns, re)
			}
		}
	}

	// Build blocklist set for O(1) lookup
	blocked := make(map[string]bool, len(p.BlockedVars))
	for _, v := range p.BlockedVars {
		blocked[v] = true
	}

	// Build allowlist set if specified
	var allowed map[string]bool
	if len(p.AllowedVars) > 0 {
		allowed = make(map[string]bool, len(p.AllowedVars))
		for _, v := range p.AllowedVars {
			allowed[v] = true
		}
	}

	result := make([]string, 0, len(env))
	for _, e := range env {
		parts := strings.SplitN(e, "=", 2)
		if len(parts) != 2 {
			continue
		}
		name := parts[0]

		// Check allowlist (if specified)
		if allowed != nil && !allowed[name] {
			continue
		}

		// Check blocklist
		if blocked[name] {
			continue
		}

		// Check patterns
		if p.matchesBlockedPattern(name) {
			continue
		}

		result = append(result, e)
	}

	return result
}

// matchesBlockedPattern checks if a variable name matches any blocked pattern.
func (p *EnvironmentPolicy) matchesBlockedPattern(name string) bool {
	for _, re := range p.compiledPatterns {
		if re.MatchString(name) {
			return true
		}
	}
	return false
}

