package policy

import "slices"

// NetworkPolicy defines network access constraints for a sandbox.
type NetworkPolicy struct {
	// AllowedHosts is a list of hostnames that are allowed for egress.
	// If empty, all egress is blocked by default.
	AllowedHosts []string

	// AllowedPorts is a list of ports that are allowed for egress.
	// If empty, all ports are allowed for hosts in AllowedHosts.
	AllowedPorts []int

	// BlockAllEgress blocks all outbound network connections when true.
	// This takes precedence over AllowedHosts.
	BlockAllEgress bool
}

// DefaultNetworkPolicy returns a NetworkPolicy with secure defaults.
// By default, all egress is blocked.
func DefaultNetworkPolicy() *NetworkPolicy {
	return &NetworkPolicy{
		BlockAllEgress: true,
		AllowedHosts:   nil,
		AllowedPorts:   nil,
	}
}

// AllowHost adds a host to the allowed list.
func (p *NetworkPolicy) AllowHost(host string) {
	p.AllowedHosts = append(p.AllowedHosts, host)
}

// AllowPort adds a port to the allowed list.
func (p *NetworkPolicy) AllowPort(port int) {
	p.AllowedPorts = append(p.AllowedPorts, port)
}

// IsHostAllowed returns true if the given host is allowed.
func (p *NetworkPolicy) IsHostAllowed(host string) bool {
	if p.BlockAllEgress {
		return false
	}
	if len(p.AllowedHosts) == 0 {
		return false
	}
	return slices.Contains(p.AllowedHosts, host)
}

