//go:build darwin

package sandbox

import (
	"context"
	"fmt"
	"net"
	"runtime"

	"github.com/jingkaihe/matchlock/pkg/api"
	matchlocksandbox "github.com/jingkaihe/matchlock/pkg/sandbox"
)

// darwinRuntime implements Runtime using Matchlock with Apple Virtualization.framework.
type darwinRuntime struct {
	kernelPath    string
	initramfsPath string
	rootfsPath    string
}

// NewRuntime creates a new Darwin runtime using Virtualization.framework via Matchlock.
func NewRuntime() (Runtime, error) {
	// Virtualization.framework is only available on Apple Silicon
	if runtime.GOARCH != "arm64" {
		return nil, fmt.Errorf("%w: darwin/amd64 not supported", ErrUnsupportedPlatform)
	}

	return &darwinRuntime{
		kernelPath:    matchlocksandbox.DefaultKernelPath(),
		initramfsPath: matchlocksandbox.DefaultInitramfsPath(),
		rootfsPath:    "", // Must be set via config
	}, nil
}

// Create creates a new VM using Virtualization.framework via Matchlock.
func (r *darwinRuntime) Create(ctx context.Context, config *Config) (VM, error) {
	if config == nil {
		config = &Config{}
	}

	// Build Matchlock API config
	apiConfig := &api.Config{
		Resources: &api.Resources{
			CPUs:       1,
			MemoryMB:   512,
			DiskSizeMB: 1024,
		},
	}

	if config.Resources != nil {
		if config.Resources.CPUs > 0 {
			apiConfig.Resources.CPUs = config.Resources.CPUs
		}
		if config.Resources.MemoryMB > 0 {
			apiConfig.Resources.MemoryMB = config.Resources.MemoryMB
		}
		if config.Resources.DiskMB > 0 {
			apiConfig.Resources.DiskSizeMB = config.Resources.DiskMB
		}
	}

	// Configure VFS for workspace mounting
	if config.WorkspaceRoot != "" {
		workspace := "/workspace"
		if config.Policy != nil && config.Policy.Filesystem != nil &&
			config.Policy.Filesystem.WorkspaceMountPoint != "" {
			workspace = config.Policy.Filesystem.WorkspaceMountPoint
		}

		apiConfig.VFS = &api.VFSConfig{
			Workspace: workspace,
			Mounts: map[string]api.MountConfig{
				workspace: {
					Type:     "real_fs",
					HostPath: config.WorkspaceRoot,
				},
			},
		}
	}

	// Configure network policy
	if config.Policy != nil && config.Policy.Network != nil {
		apiConfig.Network = &api.NetworkConfig{
			BlockPrivateIPs: true,
		}
		if !config.Policy.Network.BlockAllEgress {
			apiConfig.Network.AllowedHosts = config.Policy.Network.AllowedHosts
		}
	}

	// Determine rootfs path
	rootfsPath := config.Image
	if rootfsPath == "" {
		rootfsPath = r.rootfsPath
	}
	if rootfsPath == "" {
		return nil, fmt.Errorf("rootfs image path required")
	}

	// Create Matchlock sandbox
	opts := &matchlocksandbox.Options{
		KernelPath:    r.kernelPath,
		InitramfsPath: r.initramfsPath,
		RootfsPath:    rootfsPath,
	}

	sb, err := matchlocksandbox.New(ctx, apiConfig, opts)
	if err != nil {
		return nil, fmt.Errorf("create matchlock sandbox: %w", err)
	}

	// Start the VM
	if err := sb.Start(ctx); err != nil {
		_ = sb.Close(ctx)
		return nil, fmt.Errorf("start sandbox: %w", err)
	}

	return &darwinVM{
		id:      sb.ID(),
		state:   VMStateRunning,
		config:  config,
		sandbox: sb,
	}, nil
}

// darwinVM represents a macOS VM managed by Matchlock.
type darwinVM struct {
	id      string
	state   VMState
	config  *Config
	sandbox *matchlocksandbox.Sandbox
}

// ID returns the VM identifier.
func (v *darwinVM) ID() string {
	return v.id
}

// State returns the VM state.
func (v *darwinVM) State() VMState {
	return v.state
}

// AgentConn returns a connection to the guest agent.
// On Darwin with Matchlock, we use the exec relay socket.
func (v *darwinVM) AgentConn() (net.Conn, error) {
	// Matchlock doesn't expose a direct vsock connection in its API.
	// Instead, commands are executed via sandbox.Exec().
	return nil, fmt.Errorf("darwin runtime uses Matchlock exec, not agent connection")
}

// Sandbox returns the underlying Matchlock sandbox for direct command execution.
func (v *darwinVM) Sandbox() *matchlocksandbox.Sandbox {
	return v.sandbox
}

// Exec executes a command in the VM using Matchlock's built-in mechanism.
func (v *darwinVM) Exec(ctx context.Context, command string, opts *ExecOptions) (*ExecResult, error) {
	matchlockOpts := &api.ExecOptions{}
	if opts != nil {
		matchlockOpts.WorkingDir = opts.WorkingDir
		matchlockOpts.Env = opts.Env
		matchlockOpts.User = opts.User
		matchlockOpts.Stdin = opts.Stdin
		matchlockOpts.Stdout = opts.Stdout
		matchlockOpts.Stderr = opts.Stderr
	}

	result, err := v.sandbox.Exec(ctx, command, matchlockOpts)
	if err != nil {
		return nil, err
	}

	return &ExecResult{
		ExitCode: result.ExitCode,
		Stdout:   result.Stdout,
		Stderr:   result.Stderr,
	}, nil
}

// WriteFile writes a file to the VM's VFS.
func (v *darwinVM) WriteFile(ctx context.Context, path string, content []byte, mode uint32) error {
	return v.sandbox.WriteFile(ctx, path, content, mode)
}

// ReadFile reads a file from the VM's VFS.
func (v *darwinVM) ReadFile(ctx context.Context, path string) ([]byte, error) {
	return v.sandbox.ReadFile(ctx, path)
}

// Close stops and destroys the VM.
func (v *darwinVM) Close() error {
	v.state = VMStateStopped
	return v.sandbox.Close(context.Background())
}

// Ensure darwinVM implements ExecutableVM
var _ ExecutableVM = (*darwinVM)(nil)

