	"github.com/unstablebuild/rune-go-sdk/sandbox/sandboxrpc"
	"google.golang.org/grpc"
)

// mockRuntime is a mock implementation of Runtime for testing.
type mockRuntime struct {
	vmCounter atomic.Int64
	CreateErr error
}

func newMockRuntime() *mockRuntime {
	return &mockRuntime{}
}

func (r *mockRuntime) Create(_ context.Context, config *Config) (VM, error) {
	if r.CreateErr != nil {
		return nil, r.CreateErr
	}

	id := fmt.Sprintf("mock-vm-%d", r.vmCounter.Add(1))
	vm := &mockVM{
		id:     id,
		state:  VMStateRunning,
		config: config,
	}

	if err := vm.startAgentServer(); err != nil {
		return nil, fmt.Errorf("start agent server: %w", err)
	}

	return vm, nil
}

// mockVM is a mock implementation of VM for testing.
type mockVM struct {
	id         string
	state      VMState
	config     *Config
	grpcServer *grpc.Server
	listener   net.Listener
	sockPath   string
}

func (v *mockVM) ID() string {
	return v.id
}

func (v *mockVM) State() VMState {
	return v.state
}

func (v *mockVM) AgentConn() (net.Conn, error) {
	return net.Dial("unix", v.sockPath)
}

func (v *mockVM) Close() error {
	v.state = VMStateStopped
	if v.grpcServer != nil {
		v.grpcServer.Stop()
	}
	if v.listener != nil {
		_ = v.listener.Close()
	}
	return nil
}

func (v *mockVM) startAgentServer() error {
	// Use /tmp directly to keep path short (macOS has 104 byte limit)
	v.sockPath = filepath.Join("/tmp", fmt.Sprintf("sb-%s.sock", v.id))

	lis, err := net.Listen("unix", v.sockPath)
	if err != nil {
		return fmt.Errorf("listen: %w", err)
	}
	v.listener = lis

	v.grpcServer = grpc.NewServer()
	sandboxrpc.RegisterAgentServer(v.grpcServer, sandboxrpc.NewServer())

	go func() {
		_ = v.grpcServer.Serve(lis)
	}()

	return nil
}

