		{
			name:    "empty path",
			cmd:     workspaceapi.Cmd{},
			wantErr: ErrInvalidCommand,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			stdout := &bytes.Buffer{}
			watchCh := make(chan error, 1)
			tc.cmd.Stdout = stdout
			tc.cmd.Watcher = &testWatcher{ch: watchCh}

			ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
			defer cancel()

			pid, err := exec.Start(ctx, tc.cmd)
			if tc.wantErr != nil {
				require.ErrorIs(t, err, tc.wantErr)
				return
			}
			require.NoError(t, err)
			assert.NotZero(t, pid)

			// Wait for command to complete
			select {
			case <-watchCh:
			case <-ctx.Done():
				t.Fatal("timeout waiting for command")
			}
		})
	}
}

func TestExecutor_Signal(t *testing.T) {
	mock := newMockRuntime()
	config := DefaultConfig()
	config.WorkspaceRoot = t.TempDir()

	exec, err := New(context.Background(), config, WithRuntime(mock))
	require.NoError(t, err)
	defer func() { _ = exec.Close() }()

	tsuite := []struct {
		name    string
		pid     workspaceapi.Pid
		sig     syscall.Signal
		wantErr error
	}{
		{
			name:    "invalid pid zero",
			pid:     0,
			sig:     syscall.SIGTERM,
			wantErr: ErrProcessNotFound,
		},
		{
			name:    "invalid pid negative",
			pid:     -1,
			sig:     syscall.SIGTERM,
			wantErr: ErrProcessNotFound,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			err := exec.Signal(tc.pid, tc.sig)
			if tc.wantErr != nil {
				require.ErrorIs(t, err, tc.wantErr)
				return
			}
			require.NoError(t, err)
		})
	}
}

func TestExecutor_Signal_ValidPid(t *testing.T) {
	mock := newMockRuntime()
	config := DefaultConfig()
	config.WorkspaceRoot = "/tmp"

	exec, err := New(context.Background(), config, WithRuntime(mock))
	require.NoError(t, err)
	defer func() { _ = exec.Close() }()

	// Start a long-running process
	watchCh := make(chan error, 1)
	cmd := workspaceapi.Cmd{
		Path:    "/bin/sleep",
		Args:    []string{"60"},
		Watcher: &testWatcher{ch: watchCh},
	}

	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	pid, err := exec.Start(ctx, cmd)
	require.NoError(t, err)
	assert.NotZero(t, pid)

	// Give it time to start
	time.Sleep(100 * time.Millisecond)

	// Send SIGTERM
	err = exec.Signal(pid, syscall.SIGTERM)
	require.NoError(t, err)

	// Wait for process to terminate
	select {
	case werr := <-watchCh:
		// Process should have been terminated by signal, so we expect an error
		// The error may be about the signal or context cancellation
		assert.NotNil(t, werr)
	case <-ctx.Done():
		t.Fatal("timeout waiting for signal")
	}
}

func TestExecutor_Close(t *testing.T) {
	mock := newMockRuntime()
	config := DefaultConfig()
	config.WorkspaceRoot = t.TempDir()

	exec, err := New(context.Background(), config, WithRuntime(mock))
	require.NoError(t, err)

	// Close should succeed
	err = exec.Close()
	require.NoError(t, err)

	// Operations after close should fail
	_, err = exec.Start(context.Background(), workspaceapi.Cmd{Path: "/bin/echo"})
	require.ErrorIs(t, err, ErrClosed)

	err = exec.Signal(1, syscall.SIGTERM)
	require.ErrorIs(t, err, ErrClosed)

	// Double close should be safe
	err = exec.Close()
	require.NoError(t, err)
}

func TestExecutor_Config(t *testing.T) {
	mock := newMockRuntime()
