package policy

import (
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestDefaultPolicy(t *testing.T) {
	p := DefaultPolicy()
	require.NotNil(t, p)
	require.NotNil(t, p.Network)
	require.NotNil(t, p.Filesystem)
	require.NotNil(t, p.Audit)
}

func TestNetworkPolicy_IsHostAllowed(t *testing.T) {
	tsuite := []struct {
		name        string
		policy      *NetworkPolicy
		host        string
		wantAllowed bool
	}{
		{
			name:        "block all egress",
			policy:      &NetworkPolicy{BlockAllEgress: true},
			host:        "example.com",
			wantAllowed: false,
		},
		{
			name:        "empty allowed hosts",
			policy:      &NetworkPolicy{BlockAllEgress: false, AllowedHosts: nil},
			host:        "example.com",
			wantAllowed: false,
		},
		{
			name:        "host in allowed list",
			policy:      &NetworkPolicy{BlockAllEgress: false, AllowedHosts: []string{"api.github.com"}},
			host:        "api.github.com",
			wantAllowed: true,
		},
		{
			name:        "host not in allowed list",
			policy:      &NetworkPolicy{BlockAllEgress: false, AllowedHosts: []string{"api.github.com"}},
			host:        "google.com",
			wantAllowed: false,
		},
		{
			name:        "block all takes precedence",
			policy:      &NetworkPolicy{BlockAllEgress: true, AllowedHosts: []string{"example.com"}},
			host:        "example.com",
			wantAllowed: false,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			got := tc.policy.IsHostAllowed(tc.host)
			assert.Equal(t, tc.wantAllowed, got)
		})
	}
}

func TestNetworkPolicy_AllowHost(t *testing.T) {
	p := &NetworkPolicy{}
	p.AllowHost("example.com")
	p.AllowHost("api.github.com")

	assert.Len(t, p.AllowedHosts, 2)
	assert.Contains(t, p.AllowedHosts, "example.com")
	assert.Contains(t, p.AllowedHosts, "api.github.com")
}

func TestNetworkPolicy_AllowPort(t *testing.T) {
	p := &NetworkPolicy{}
	p.AllowPort(80)
	p.AllowPort(443)

	assert.Len(t, p.AllowedPorts, 2)
	assert.Contains(t, p.AllowedPorts, 80)
	assert.Contains(t, p.AllowedPorts, 443)
}

func TestFilesystemPolicy_AddReadOnlyPath(t *testing.T) {
	p := DefaultFilesystemPolicy()
	initialLen := len(p.ReadOnlyPaths)

	p.AddReadOnlyPath("/etc")
	assert.Len(t, p.ReadOnlyPaths, initialLen+1)
	assert.Contains(t, p.ReadOnlyPaths, "/etc")
}

func TestFilesystemPolicy_AddHiddenPath(t *testing.T) {
	p := DefaultFilesystemPolicy()

	p.AddHiddenPath("/secrets")
	assert.Len(t, p.HiddenPaths, 1)
	assert.Contains(t, p.HiddenPaths, "/secrets")
}

func TestDefaultFilesystemPolicy(t *testing.T) {
	p := DefaultFilesystemPolicy()

	assert.True(t, p.EphemeralRoot)
	assert.Equal(t, "/workspace", p.WorkspaceMountPoint)
	assert.NotEmpty(t, p.ReadOnlyPaths)
}

func TestDefaultNetworkPolicy(t *testing.T) {
	p := DefaultNetworkPolicy()

	assert.True(t, p.BlockAllEgress)
	assert.Nil(t, p.AllowedHosts)
	assert.Nil(t, p.AllowedPorts)
}

func TestDefaultAuditPolicy(t *testing.T) {
	p := DefaultAuditPolicy()

	assert.True(t, p.LogCommands)
	assert.False(t, p.LogNetwork)
	assert.False(t, p.LogFilesystem)
}

