   193→		if msg.GetType() != CommandMessage_TYPE_IO {
   194→			continue
   195→		}
   196→
   197→		io := msg.GetIo()
   198→		if io == nil || io.GetType() != IOData_IO_STDIN {
   199→			continue
   200→		}
   201→
   202→		_, err = stdin.Write(io.GetData())
