func TestNetworkPolicy_SecurityInvariants(t *testing.T) {
	// This test verifies critical security invariants of the network policy

	t.Run("default policy blocks all egress", func(t *testing.T) {
		p := DefaultNetworkPolicy()

		// Must block by default - this is a security requirement
		assert.True(t, p.BlockAllEgress,
			"SECURITY: default network policy must block all egress")

		// Verify common dangerous hosts are blocked
		dangerousHosts := []string{
			"evil.com",
			"169.254.169.254", // AWS metadata service
			"metadata.google.internal",
			"localhost",
			"127.0.0.1",
			"0.0.0.0",
		}
		for _, host := range dangerousHosts {
			assert.False(t, p.IsHostAllowed(host),
				"SECURITY: host %q must be blocked by default", host)
		}
	})

	t.Run("BlockAllEgress overrides allowlist", func(t *testing.T) {
		p := &NetworkPolicy{
			BlockAllEgress: true,
			AllowedHosts:   []string{"api.github.com", "example.com"},
		}

		// Even though hosts are in allowlist, BlockAllEgress takes precedence
		assert.False(t, p.IsHostAllowed("api.github.com"),
			"SECURITY: BlockAllEgress must override allowlist")
		assert.False(t, p.IsHostAllowed("example.com"),
			"SECURITY: BlockAllEgress must override allowlist")
	})

	t.Run("empty allowlist blocks all", func(t *testing.T) {
		p := &NetworkPolicy{
			BlockAllEgress: false,
			AllowedHosts:   nil, // Empty allowlist
		}

		// No hosts should be allowed when allowlist is empty
		assert.False(t, p.IsHostAllowed("any-host.com"),
			"SECURITY: empty allowlist must block all hosts")
	})

	t.Run("allowlist is exact match only", func(t *testing.T) {
		p := &NetworkPolicy{
			BlockAllEgress: false,
			AllowedHosts:   []string{"api.github.com"},
		}

		// Exact match should work
		assert.True(t, p.IsHostAllowed("api.github.com"))

		// Subdomains should NOT match (no wildcard support)
		assert.False(t, p.IsHostAllowed("evil.api.github.com"),
			"SECURITY: subdomain should not match allowed host")
		assert.False(t, p.IsHostAllowed("api.github.com.evil.com"),
			"SECURITY: suffix attack should not match allowed host")

		// Similar names should NOT match
		assert.False(t, p.IsHostAllowed("api.github.com.attacker.com"))
		assert.False(t, p.IsHostAllowed("github.com"))
	})
}

