func TestE2E_ReadOnlyPaths(t *testing.T) {
	config := DefaultConfig()

	// Ensure default read-only paths are set
	require.NotNil(t, config.Policy)
	require.NotNil(t, config.Policy.Filesystem)
	require.NotEmpty(t, config.Policy.Filesystem.ReadOnlyPaths)

	exec := setupE2EExecutor(t, config)

	// Verify system paths are read-only
	tsuite := []struct {
		name string
		path string
		cmd  string
	}{
		{
			name: "/usr is read-only",
			path: "/usr",
			cmd:  "touch /usr/testfile 2>&1",
		},
		{
			name: "/bin is read-only",
			path: "/bin",
			cmd:  "touch /bin/testfile 2>&1",
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			stdout, _ := runCommand(t, exec, tc.cmd)
			// Should fail with permission denied or read-only filesystem error
			assert.True(t,
				strings.Contains(stdout, "Read-only") ||
					strings.Contains(stdout, "Permission denied") ||
					strings.Contains(stdout, "Operation not permitted"),
				"write to %s should fail, got: %s", tc.path, stdout)
		})
	}
}

func TestE2E_HostFilesystemIsolation(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	// Verify sandbox cannot access host-specific paths
	hostPaths := []string{
		"/etc/passwd",        // Should exist but be sandbox's own
		"/etc/shadow",        // Should not be readable
		"/root",              // Should not have host's root home
		"/home",              // Should not have host's home directories
		"/Users",             // macOS home directories
		"/var/run/docker.sock", // Docker socket
	}

	for _, path := range hostPaths {
		t.Run(path, func(t *testing.T) {
			// Try to read the file
			stdout, stderr := runCommand(t, exec,
				fmt.Sprintf("cat %s 2>&1 || echo 'NOT_ACCESSIBLE'", path))

			combined := stdout + stderr

			// If the file exists, it should be the sandbox's version, not the host's
			// We verify by checking for common host-specific content
			if !strings.Contains(combined, "NOT_ACCESSIBLE") &&
				!strings.Contains(combined, "No such file") &&
				!strings.Contains(combined, "Permission denied") {
				// File is accessible - verify it's not the host's version
				if path == "/etc/passwd" {
					// Sandbox's passwd should not contain host usernames
					// (This is a heuristic check)
					assert.NotContains(t, stdout, os.Getenv("USER"),
						"sandbox /etc/passwd should not contain host username")
				}
			}
		})
	}
}

func TestE2E_NoHostNetworkNamespace(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	// Verify sandbox has its own network namespace
	// by checking that host network interfaces are not visible

	// Get network interfaces in sandbox
	stdout, _ := runCommand(t, exec, "ip link show 2>/dev/null || ifconfig -a 2>/dev/null || echo 'NO_NET_TOOLS'")

	if strings.Contains(stdout, "NO_NET_TOOLS") {
		t.Skip("network tools not available in sandbox image")
	}

	// Common host-only interfaces that should NOT appear in sandbox
	hostInterfaces := []string{
		"docker0",   // Docker bridge
		"br-",       // Docker custom bridges
		"veth",      // Docker veth pairs
		"virbr",     // libvirt bridges
		"vmnet",     // VMware interfaces
		"en0",       // macOS primary interface (should have different name in VM)
		"enp",       // Linux physical interfaces
		"wlp",       // Linux wireless interfaces
	}

	for _, iface := range hostInterfaces {
		// Note: Some of these might legitimately appear in a VM
		// This is a heuristic check
		if strings.Contains(stdout, iface) {
			t.Logf("Warning: interface %q visible in sandbox (may be false positive)", iface)
		}
	}

	// Verify sandbox has at least a loopback interface
	assert.True(t,
		strings.Contains(stdout, "lo") || strings.Contains(stdout, "loopback"),
		"sandbox should have loopback interface")
}

func TestE2E_TimeIsolation(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	// Verify the sandbox has a reasonable time
	// (not checking exact match to avoid flakiness, just sanity check)
	stdout, _ := runCommand(t, exec, "date +%Y")

	var year int
	_, err := fmt.Sscanf(strings.TrimSpace(stdout), "%d", &year)
	require.NoError(t, err, "failed to parse year from sandbox")

	// Year should be reasonable (not 1970, not far future)
	assert.GreaterOrEqual(t, year, 2024, "sandbox year should be reasonable")
	assert.LessOrEqual(t, year, 2030, "sandbox year should be reasonable")
}

